const e={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Sieh, wie die Steuerungsplatinen deines Druckers verbunden sind: der Host (SBC) und jeder MCU, mit dem er kommuniziert, samt Verbindungstyp und einer bestmöglichen Schätzung von Platine / Chip — live aus der Konfiguration ausgelesen."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über Board-Topologie"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"So liest du es"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Der Host (dein SBC, z. B. ein Raspberry Pi oder CB1) steht ganz oben."}},{t:0,b:{t:2,i:[{t:3}],s:"Jede MCU-Karte zeigt, wie sie verbunden ist (USB / CAN bus / UART) und ihren Chip."}},{t:0,b:{t:2,i:[{t:3}],s:"Eine Platinen-Schätzung erscheint, wenn die Verbindungskennung mit einer bekannten Platine übereinstimmt."}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCUs"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Ein MCU ist eine Mikrocontroller-Platine, die Motoren, Heizungen und Sensoren ansteuert. Ein Drucker hat mindestens einen (das Mainboard); viele ergänzen eine Toolhead-Platine und manchmal eine Probe- oder LED-Platine. Dieses Panel listet jede `[mcu]`-Sektion auf, die Klipper kennt."}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Verbindungstypen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB — eine Serial-over-USB-Verbindung (die übliche Mainboard-Anbindung). CAN bus — ein gemeinsam genutzter Zweidraht-Bus, üblich für Toolhead-Platinen. UART — eine direkte serielle Verbindung über GPIO. Der Typ wird aus der `serial`- / `canbus_uuid`-Einstellung jedes MCUs abgeleitet."}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"Wie die Erkennung funktioniert"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Chip und Board werden ermittelt, indem die Verbindungskennung (der serielle Pfad oder die CAN-UUID) mit einer Mustertabelle abgeglichen wird, plus einem Pin-Map-Fingerabdruck der von deiner Konfiguration genutzten Pins. Eine Board-Vermutung zeigt eine Treffersicherheit; passt nichts, steht bei Chip/Board „unbekannt“ — die Verbindung selbst wird weiterhin angezeigt."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}},override:{title:{t:0,b:{t:2,i:[{t:3}],s:"Board bestätigen oder ändern"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Eine Serien-ID verrät meist nur den Chip, daher kann die Board-Vermutung fehlen oder falsch sein. Nutze „Dieses Board bestätigen“, um eine richtige Vermutung festzulegen, oder „Board ändern…“ / „Board festlegen…“, um das passende aus dem Katalog zu wählen. Deine Auswahl wird auf dem Host gespeichert und bei jedem Auslesen wiederverwendet; „Zurücksetzen“ stellt die automatische Vermutung wieder her."}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Microcontroller Unit — eine Steuerplatine, auf der Klippers Firmware läuft (Mainboard, Toolhead usw.)."}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein gemeinsam genutzter Zweidraht-Bus, der Platinen über eine eindeutige UUID verbindet — beliebt für die Toolhead-Verkabelung."}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Der Einplatinencomputer (Pi, CB1, …), auf dem Klipper läuft und der mit den MCUs kommuniziert."}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},role:{t:0,b:{t:2,i:[{t:3}],s:"Einplatinencomputer — führt Klipper aus"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"Chip"}},board:{t:0,b:{t:2,i:[{t:3}],s:"Platine"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"unbekannt"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"Kennung"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:"% Übereinstimmung"}]}},viewBoard:{t:0,b:{t:2,i:[{t:3}],s:"Board-Details anzeigen"}},hideBoard:{t:0,b:{t:2,i:[{t:3}],s:"Details ausblenden"}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"unbekannt"}},via:{t:0,b:{t:2,i:[{t:3,v:"über "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" MCUs"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Topologie wird gelesen…"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Der Drucker war nicht erreichbar."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Keine MCUs in der Konfiguration gefunden."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Erneut versuchen"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Aktualisieren"}}},board:{suggested:{t:0,b:{t:2,i:[{t:3}],s:"Vorschlag"}},ports:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" Anschlüsse"}]}},specsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Daten"}},portsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Anschlüsse"}},none:{t:0,b:{t:2,i:[{t:3}],s:"Noch keine Katalogdetails für dieses Board."}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Board wird geladen…"}},links:{title:{t:0,b:{t:2,i:[{t:3}],s:"Links"}},product:{t:0,b:{t:2,i:[{t:3}],s:"Produkt"}},repo:{t:0,b:{t:2,i:[{t:3}],s:"Repo"}},wiki:{t:0,b:{t:2,i:[{t:3}],s:"Wiki"}},pinout:{t:0,b:{t:2,i:[{t:3}],s:"Pinbelegung"}},schematic:{t:0,b:{t:2,i:[{t:3}],s:"Schaltplan"}},datasheet:{t:0,b:{t:2,i:[{t:3}],s:"Datenblatt"}},image:{t:0,b:{t:2,i:[{t:3}],s:"Foto"}}}},components:{title:{t:0,b:{t:2,i:[{t:3}],s:"Komponenten"}},motor:{t:0,b:{t:2,i:[{t:3}],s:"Motoren"}},driver:{t:0,b:{t:2,i:[{t:3}],s:"Treiber"}},heater:{t:0,b:{t:2,i:[{t:3}],s:"Heizer"}},fan:{t:0,b:{t:2,i:[{t:3}],s:"Lüfter"}},sensor:{t:0,b:{t:2,i:[{t:3}],s:"Sensoren"}}},sync:{synced:{t:0,b:{t:2,i:[{t:3}],s:"Firmware synchron"}},outOfSync:{t:0,b:{t:2,i:[{t:3}],s:"Firmware NICHT synchron"}}},override:{confirmed:{t:0,b:{t:2,i:[{t:3}],s:"Von dir bestätigt"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Dieses Board bestätigen"}},change:{t:0,b:{t:2,i:[{t:3}],s:"Board ändern…"}},set:{t:0,b:{t:2,i:[{t:3}],s:"Board festlegen…"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Zurücksetzen"}},pickPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Board-Katalog durchsuchen…"}},hint:{t:0,b:{t:2,i:[{t:3}],s:"Deine Auswahl wird auf dem Host gespeichert und ab jetzt für diesen MCU verwendet."}}}}};export{e as default};
